"use strict";(self.webpackChunkspanish_app=self.webpackChunkspanish_app||[]).push([[3141],{3141:e=>{e.exports=JSON.parse('{"29":{"words":[{"spanish":"He hecho varios cursos","english":"I have taken several courses"},{"spanish":"Has dicho la verdad","english":"You have told the truth"},{"spanish":"Ha escrito un informe","english":"He or she has written a report"},{"spanish":"Hemos visto cambios","english":"We have seen changes"},{"spanish":"Han puesto nuevas reglas","english":"They have put in new rules"},{"spanish":"He roto mi tel\xe9fono","english":"I have broken my phone"},{"spanish":"Ha vuelto temprano","english":"He or she has returned early"},{"spanish":"He abierto una cuenta","english":"I have opened an account"},{"spanish":"Se han muerto las plantas","english":"The plants have died"},{"spanish":"Hemos descubierto un error","english":"We have discovered an error"},{"spanish":"He resuelto un problema","english":"I have solved a problem"},{"spanish":"Has aprendido mucho","english":"You have learned a lot"},{"spanish":"Ha terminado el proyecto","english":"He or she has finished the project"},{"spanish":"Hemos logrado la meta","english":"We have achieved the goal"},{"spanish":"Han conseguido clientes nuevos","english":"They have gained new clients"},{"spanish":"He visitado tres pa\xedses","english":"I have visited three countries"},{"spanish":"\xbfHas probado este plato?","english":"Have you tried this dish?"},{"spanish":"Todav\xeda no he respondido","english":"I still have not replied"},{"spanish":"Ya hemos enviado el contrato","english":"We have already sent the contract"},{"spanish":"Nunca he conducido en nieve","english":"I have never driven in snow"},{"spanish":"Recientemente","english":"Recently"},{"spanish":"Hasta ahora","english":"So far"},{"spanish":"\xdaltimamente","english":"Lately"},{"spanish":"Esta semana","english":"This week"},{"spanish":"Este mes","english":"This month"},{"spanish":"A lo largo de mi vida","english":"Throughout my life"},{"spanish":"La experiencia laboral","english":"Work experience"},{"spanish":"El logro reciente","english":"The recent achievement"},{"spanish":"La tarea terminada","english":"The completed task"},{"spanish":"El informe final","english":"The final report"},{"spanish":"La exposici\xf3n abierta","english":"The exhibition that has opened"},{"spanish":"La puerta rota","english":"The broken door"},{"spanish":"La verdad dicha","english":"The truth that has been told"},{"spanish":"El correo enviado","english":"The email that has been sent"},{"spanish":"La cuenta bancaria","english":"The bank account"},{"spanish":"El descubrimiento cient\xedfico","english":"The scientific discovery"},{"spanish":"La mejora notable","english":"The notable improvement"},{"spanish":"El cambio inesperado","english":"The unexpected change"},{"spanish":"La meta cumplida","english":"The fulfilled goal"},{"spanish":"La beca conseguida","english":"The scholarship that has been obtained"},{"spanish":"La reparaci\xf3n urgente","english":"The urgent repair"},{"spanish":"El viaje inolvidable","english":"The unforgettable trip"}],"conversations":[{"id":1,"topic":"Experiencia laboral en una entrevista","dialog":[{"speaker":"Daniela","spanish":"He le\xeddo tu curr\xedculum y veo que has trabajado en tres organizaciones sociales durante los \xfaltimos cinco a\xf1os.","english":"I have read your r\xe9sum\xe9 and I see that you have worked in three social organizations over the last five years."},{"speaker":"Roberto","spanish":"S\xed, y adem\xe1s he coordinado campa\xf1as locales. Este a\xf1o tambi\xe9n he escrito dos propuestas de financiamiento.","english":"Yes, and I have also coordinated local campaigns. This year I have written two funding proposals as well."},{"speaker":"Daniela","spanish":"Interesante. \xbfHas dirigido equipos grandes o solo grupos peque\xf1os?","english":"Interesting. Have you led large teams or only small groups?"},{"speaker":"Roberto","spanish":"He dirigido un equipo de doce personas y hemos logrado aumentar bastante la participaci\xf3n vecinal.","english":"I have led a team of twelve people and we have managed to increase neighborhood participation quite a bit."},{"speaker":"Daniela","spanish":"Eso suena valioso. Tambi\xe9n noto que has vuelto recientemente de Medell\xedn. \xbfQu\xe9 has aprendido all\xed?","english":"That sounds valuable. I also notice that you have recently returned from Medell\xedn. What have you learned there?"},{"speaker":"Roberto","spanish":"He aprendido a negociar con instituciones p\xfablicas y he descubierto formas m\xe1s eficientes de medir el impacto.","english":"I have learned to negotiate with public institutions and I have discovered more efficient ways to measure impact."}],"questions":[{"question":"\xbfQu\xe9 ha escrito Roberto este a\xf1o?","options":["Dos propuestas de financiamiento","Un libro sobre liderazgo","Tres informes m\xe9dicos","Un contrato de alquiler"],"answerIndex":0,"answer":"Dos propuestas de financiamiento"},{"question":"\xbfDe cu\xe1ntas personas ha dirigido Roberto un equipo?","options":["De ocho personas","De diez personas","De doce personas","De veinte personas"],"answerIndex":2,"answer":"De doce personas"},{"question":"\xbfQu\xe9 dice Roberto que ha aprendido en Medell\xedn?","options":["A dise\xf1ar campa\xf1as de moda","A negociar con instituciones p\xfablicas y medir mejor el impacto","A programar aplicaciones m\xf3viles","A ense\xf1ar matem\xe1ticas en l\xednea"],"answerIndex":1,"answer":"A negociar con instituciones p\xfablicas y medir mejor el impacto"}]},{"id":2,"topic":"Una reparaci\xf3n urgente en casa","dialog":[{"speaker":"In\xe9s","spanish":"Vaya ma\xf1ana. Se ha roto la tuber\xeda de la cocina y el agua ha entrado hasta el pasillo.","english":"What a morning. The kitchen pipe has broken and the water has spread all the way into the hallway."},{"speaker":"Marcos","spanish":"Qu\xe9 desastre. \xbfHas llamado ya al fontanero o todav\xeda no has podido?","english":"What a disaster. Have you called the plumber yet or have you still not been able to?"},{"speaker":"In\xe9s","spanish":"S\xed, ha venido hace una hora, ha cerrado la llave principal y ha dicho que necesitar\xe9 una pieza nueva.","english":"Yes, he came an hour ago, shut off the main valve, and said I would need a new part."},{"speaker":"Marcos","spanish":"Al menos ha llegado r\xe1pido. \xbfHan puesto alguna fecha para terminar la reparaci\xf3n?","english":"At least he arrived quickly. Have they set any date to finish the repair?"},{"speaker":"In\xe9s","spanish":"Me ha prometido que volver\xe1n ma\xf1ana temprano. Mientras tanto, hemos movido los muebles y hemos abierto las ventanas para secar todo.","english":"He has promised me they will come back tomorrow morning. Meanwhile, we have moved the furniture and opened the windows to dry everything out."},{"speaker":"Marcos","spanish":"Bueno, dentro de lo malo, hab\xe9is reaccionado enseguida y hab\xe9is evitado un problema mayor.","english":"Well, within the bad situation, you have reacted right away and avoided a bigger problem."}],"questions":[{"question":"\xbfQu\xe9 se ha roto en la casa de In\xe9s?","options":["La pantalla del televisor","La tuber\xeda de la cocina","La puerta del garaje","La lavadora nueva"],"answerIndex":1,"answer":"La tuber\xeda de la cocina"},{"question":"\xbfQu\xe9 ha dicho el fontanero que necesitar\xe1 In\xe9s?","options":["Una cocina nueva","Una pieza nueva","Un seguro diferente","Una ventana extra"],"answerIndex":1,"answer":"Una pieza nueva"},{"question":"\xbfC\xf3mo ha reaccionado la familia mientras espera la reparaci\xf3n?","options":["Ha salido del piso y ha cerrado todo","Ha pedido ayuda a los vecinos para cocinar","Ha movido los muebles y ha abierto las ventanas","Ha cancelado el trabajo del d\xeda siguiente"],"answerIndex":2,"answer":"Ha movido los muebles y ha abierto las ventanas"}]},{"id":3,"topic":"Un proyecto universitario ya terminado","dialog":[{"speaker":"Laura","spanish":"Por fin hemos terminado la presentaci\xf3n. Yo he revisado las cifras y Marta ha hecho los gr\xe1ficos finales.","english":"At last we have finished the presentation. I have checked the figures and Marta has made the final charts."},{"speaker":"Tom\xe1s","spanish":"Excelente. Adem\xe1s, t\xfa has dicho varias veces que faltaba una conclusi\xf3n m\xe1s clara, y ten\xedas raz\xf3n.","english":"Excellent. Besides, you have said several times that a clearer conclusion was missing, and you were right."},{"speaker":"Laura","spanish":"S\xed, por eso he escrito un cierre m\xe1s breve. \xbfT\xfa has visto ya la versi\xf3n nueva?","english":"Yes, that is why I have written a shorter closing section. Have you seen the new version yet?"},{"speaker":"Tom\xe1s","spanish":"La he visto y me ha gustado mucho. Tambi\xe9n he puesto las citas bibliogr\xe1ficas en el formato correcto.","english":"I have seen it and I liked it a lot. I have also put the bibliographic citations in the correct format."},{"speaker":"Laura","spanish":"Perfecto. Si todo sale bien, habremos entregado nuestro mejor trabajo del semestre.","english":"Perfect. If everything goes well, we will have turned in our best work of the semester."},{"speaker":"Tom\xe1s","spanish":"Yo creo que s\xed; en dos semanas hemos avanzado much\xedsimo y hemos aprendido a coordinarnos mejor.","english":"I think so; in two weeks we have made huge progress and learned to coordinate better."}],"questions":[{"question":"\xbfQu\xe9 parte del trabajo ha hecho Marta?","options":["Los gr\xe1ficos finales","La bibliograf\xeda completa","La defensa oral entera","La encuesta inicial"],"answerIndex":0,"answer":"Los gr\xe1ficos finales"},{"question":"\xbfQu\xe9 ha corregido Tom\xe1s en la versi\xf3n nueva?","options":["La portada del archivo","Las citas bibliogr\xe1ficas","El calendario del curso","La traducci\xf3n al ingl\xe9s"],"answerIndex":1,"answer":"Las citas bibliogr\xe1ficas"},{"question":"\xbfQu\xe9 creen Laura y Tom\xe1s que han logrado?","options":["Han evitado presentar el proyecto","Han conseguido cambiar de profesor","Han avanzado much\xedsimo y han aprendido a coordinarse mejor","Han suspendido menos materias"],"answerIndex":2,"answer":"Han avanzado much\xedsimo y han aprendido a coordinarse mejor"}]},{"id":4,"topic":"Resultados recientes de una tienda en l\xednea","dialog":[{"speaker":"Sof\xeda","spanish":"Desde enero hemos abierto la tienda en l\xednea, hemos vendido m\xe1s de cuatrocientos cuadernos y hasta hemos conseguido clientes en Chile.","english":"Since January we have opened the online store, sold more than four hundred notebooks, and even gained customers in Chile."},{"speaker":"Gabriel","spanish":"Lo s\xe9, y t\xfa has hecho casi todo el trabajo de dise\xf1o. \xbfTambi\xe9n has hablado con la imprenta nueva?","english":"I know, and you have done almost all the design work. Have you also spoken with the new print shop?"},{"speaker":"Sof\xeda","spanish":"S\xed, he hablado con ellos esta ma\xf1ana y me han dicho que ya han puesto en marcha un sistema m\xe1s r\xe1pido.","english":"Yes, I spoke with them this morning and they told me they have already put a faster system into operation."},{"speaker":"Gabriel","spanish":"Eso nos conviene. Yo he visto los \xfaltimos pedidos y varios clientes han escrito comentarios muy positivos.","english":"That works for us. I have seen the latest orders and several clients have written very positive comments."},{"speaker":"Sof\xeda","spanish":"Qu\xe9 alivio. Despu\xe9s de tantos meses, por fin hemos descubierto qu\xe9 productos interesan m\xe1s.","english":"What a relief. After so many months, we have finally discovered which products interest people most."},{"speaker":"Gabriel","spanish":"Exacto, y gracias a eso no solo hemos crecido, sino que tambi\xe9n hemos vuelto la empresa m\xe1s organizada.","english":"Exactly, and thanks to that we have not only grown, but we have also made the company more organized."}],"questions":[{"question":"\xbfQu\xe9 han vendido Sof\xeda y Gabriel desde enero?","options":["M\xe1s de cuatrocientos cuadernos","M\xe1s de cien l\xe1mparas","Tres cursos en l\xednea","Dos colecciones de ropa"],"answerIndex":0,"answer":"M\xe1s de cuatrocientos cuadernos"},{"question":"\xbfQui\xe9n ha hecho casi todo el trabajo de dise\xf1o?","options":["Gabriel","La imprenta nueva","Sof\xeda","Los clientes de Chile"],"answerIndex":2,"answer":"Sof\xeda"},{"question":"\xbfQu\xe9 han descubierto por fin?","options":["Qu\xe9 productos interesan m\xe1s","C\xf3mo cerrar la tienda","D\xf3nde comprar otra oficina","Qu\xe9 pa\xeds tiene menos impuestos"],"answerIndex":0,"answer":"Qu\xe9 productos interesan m\xe1s"}]}],"stories":[{"id":1,"title":"Lo que hemos logrado en el taller","sentences":[{"spanish":"En los \xfaltimos seis meses, el taller de costura del barrio ha crecido m\xe1s de lo que sus fundadoras imaginaron.","english":"In the last six months, the neighborhood sewing workshop has grown more than its founders imagined."},{"spanish":"Han abierto dos grupos nuevos, han conseguido materiales donados y han vendido sus primeras colecciones en ferias locales.","english":"They have opened two new groups, obtained donated materials, and sold their first collections at local fairs."},{"spanish":"Marta ha hecho casi todas las gestiones administrativas, mientras Irene ha escrito las propuestas para nuevos apoyos.","english":"Marta has handled almost all the administrative arrangements, while Irene has written the proposals for new support."},{"spanish":"Varias alumnas han descubierto que tambi\xe9n pueden convertir su afici\xf3n en una fuente de ingresos.","english":"Several students have discovered that they can also turn their hobby into a source of income."},{"spanish":"Incluso han puesto en marcha un sistema para reciclar telas y aprovechar cada retazo posible.","english":"They have even launched a system to recycle fabric and make use of every possible scrap."},{"spanish":"Aunque todav\xeda queda mucho por mejorar, todas sienten que ya han construido algo estable y \xfatil.","english":"Although there is still a lot to improve, they all feel they have already built something stable and useful."}]},{"id":2,"title":"Una semana que ha cambiado mucho","sentences":[{"spanish":"Esta semana, Daniel ha vivido una cadena de imprevistos y soluciones r\xe1pidas.","english":"This week, Daniel has gone through a string of setbacks and quick solutions."},{"spanish":"El lunes ha roto la pantalla del port\xe1til, pero un t\xe9cnico se la ha cambiado en menos de un d\xeda.","english":"On Monday he broke his laptop screen, but a technician replaced it in less than a day."},{"spanish":"El martes ha abierto por fin la cuenta de ahorro que llevaba meses posponiendo.","english":"On Tuesday he finally opened the savings account he had been putting off for months."},{"spanish":"El mi\xe9rcoles le han dicho que su propuesta de investigaci\xf3n ha sido aceptada.","english":"On Wednesday they told him that his research proposal has been accepted."},{"spanish":"Desde entonces, ha escrito varios correos, ha puesto en orden sus papeles y ha vuelto a sentirse due\xf1o de su tiempo.","english":"Since then, he has written several emails, put his papers in order, and begun to feel in control of his time again."},{"spanish":"No todo ha sido f\xe1cil, pero estos d\xedas le han recordado que tambi\xe9n sabe reaccionar bien bajo presi\xf3n.","english":"Not everything has been easy, but these days have reminded him that he also knows how to react well under pressure."}]},{"id":3,"title":"Nunca he olvidado ese viaje","sentences":[{"spanish":"Nunca he olvidado mi tiempo en Oaxaca, porque all\xed he vivido algunas de mis conversaciones m\xe1s memorables en espa\xf1ol.","english":"I have never forgotten my time in Oaxaca because I had some of my most memorable conversations in Spanish there."},{"spanish":"He probado comidas que no conoc\xeda, he visto talleres de barro y he escuchado historias familiares durante largas sobremesas.","english":"I have tried foods I did not know, seen pottery workshops, and listened to family stories during long after-dinner conversations."},{"spanish":"Una artesana me ha dicho que cada pieza rota tambi\xe9n ense\xf1a algo, y esa frase se me ha quedado grabada.","english":"An artisan told me that every broken piece also teaches something, and that phrase has stayed with me."},{"spanish":"Desde entonces, he vuelto a leer mis notas muchas veces para no perder los detalles.","english":"Since then, I have gone back to read my notes many times so I do not lose the details."},{"spanish":"Tambi\xe9n he escrito a varias personas que conoc\xed all\xed y hemos mantenido una amistad inesperada.","english":"I have also written to several people I met there, and we have kept up an unexpected friendship."},{"spanish":"Ese viaje no solo me ha abierto el o\xeddo al idioma, sino que adem\xe1s me ha cambiado la manera de escuchar a los dem\xe1s.","english":"That trip has not only opened my ear to the language, but it has also changed the way I listen to others."}]}],"speaking":{"title":"Experiencias, logros y eventos recientes","description":"Practica el pret\xe9rito perfecto para hablar de experiencias de vida, cambios recientes y metas cumplidas.","questions_and_answers":[{"question":{"spanish":"\xbfQu\xe9 has hecho esta semana de lo que te sientes orgulloso?","english":"What have you done this week that you feel proud of?"},"answer":{"spanish":"Esta semana he terminado un proyecto que llevaba meses pendiente.","english":"This week I have finished a project that had been pending for months."}},{"question":{"spanish":"\xbfHas probado alguna comida nueva \xfaltimamente?","english":"Have you tried any new food lately?"},"answer":{"spanish":"S\xed, he probado un plato peruano muy picante.","english":"Yes, I have tried a very spicy Peruvian dish."}},{"question":{"spanish":"\xbfQu\xe9 has aprendido recientemente?","english":"What have you learned recently?"},"answer":{"spanish":"He aprendido a organizar mejor mi tiempo.","english":"I have learned to organize my time better."}},{"question":{"spanish":"\xbfHas escrito alg\xfan mensaje importante hoy?","english":"Have you written any important message today?"},"answer":{"spanish":"S\xed, he escrito un correo formal a un cliente.","english":"Yes, I have written a formal email to a client."}},{"question":{"spanish":"\xbfQu\xe9 logro ha tenido tu equipo este mes?","english":"What achievement has your team had this month?"},"answer":{"spanish":"Mi equipo ha conseguido cerrar dos acuerdos nuevos.","english":"My team has managed to close two new deals."}},{"question":{"spanish":"\xbfHas visto alguna pel\xedcula memorable este a\xf1o?","english":"Have you seen any memorable movie this year?"},"answer":{"spanish":"S\xed, he visto una pel\xedcula que me ha hecho pensar mucho.","english":"Yes, I have seen a movie that made me think a lot."}},{"question":{"spanish":"\xbfQu\xe9 has puesto en orden \xfaltimamente?","english":"What have you put in order lately?"},"answer":{"spanish":"He puesto en orden mis finanzas y mis documentos.","english":"I have put my finances and documents in order."}},{"question":{"spanish":"\xbfHas dicho algo dif\xedcil pero necesario?","english":"Have you said something difficult but necessary?"},"answer":{"spanish":"S\xed, he dicho la verdad en una conversaci\xf3n inc\xf3moda.","english":"Yes, I have told the truth in an uncomfortable conversation."}},{"question":{"spanish":"\xbfQu\xe9 has descubierto sobre ti mismo recientemente?","english":"What have you discovered about yourself recently?"},"answer":{"spanish":"He descubierto que trabajo mejor por la ma\xf1ana.","english":"I have discovered that I work better in the morning."}},{"question":{"spanish":"\xbfHas vuelto a un lugar importante para ti?","english":"Have you returned to a place that matters to you?"},"answer":{"spanish":"S\xed, he vuelto al barrio donde crec\xed.","english":"Yes, I have gone back to the neighborhood where I grew up."}},{"question":{"spanish":"\xbfQu\xe9 has abierto recientemente?","english":"What have you opened recently?"},"answer":{"spanish":"He abierto una cuenta de ahorro para viajar.","english":"I have opened a savings account for travel."}},{"question":{"spanish":"\xbfHas roto alguna mala costumbre?","english":"Have you broken any bad habit?"},"answer":{"spanish":"S\xed, he roto el h\xe1bito de revisar el tel\xe9fono antes de dormir.","english":"Yes, I have broken the habit of checking my phone before sleeping."}},{"question":{"spanish":"\xbfQu\xe9 has hecho por tu salud este mes?","english":"What have you done for your health this month?"},"answer":{"spanish":"He empezado a caminar todos los d\xedas despu\xe9s de cenar.","english":"I have started walking every day after dinner."}},{"question":{"spanish":"\xbfHas tenido alg\xfan imprevisto reciente?","english":"Have you had any recent unexpected event?"},"answer":{"spanish":"S\xed, se me ha roto una tuber\xeda y he llamado al fontanero enseguida.","english":"Yes, a pipe broke on me and I called the plumber right away."}},{"question":{"spanish":"\xbfQu\xe9 te ha dicho tu profesor o tu jefe que recuerdas bien?","english":"What has your teacher or boss told you that you remember well?"},"answer":{"spanish":"Me ha dicho que mi trabajo ha mejorado bastante.","english":"He or she has told me that my work has improved a lot."}},{"question":{"spanish":"\xbfQu\xe9 has visto cambiar en tu ciudad?","english":"What have you seen change in your city?"},"answer":{"spanish":"He visto m\xe1s ciclov\xedas y m\xe1s cafeter\xedas peque\xf1as.","english":"I have seen more bike lanes and more small caf\xe9s."}},{"question":{"spanish":"\xbfQu\xe9 ha logrado tu familia recientemente?","english":"What has your family achieved recently?"},"answer":{"spanish":"Mi familia ha logrado mudarse a una casa m\xe1s tranquila.","english":"My family has managed to move to a quieter house."}},{"question":{"spanish":"\xbfHas puesto en pr\xe1ctica algo que has aprendido?","english":"Have you put something you learned into practice?"},"answer":{"spanish":"S\xed, he puesto en pr\xe1ctica una t\xe9cnica nueva de estudio.","english":"Yes, I have put a new study technique into practice."}},{"question":{"spanish":"\xbfQu\xe9 experiencia te ha abierto nuevas ideas?","english":"What experience has opened new ideas for you?"},"answer":{"spanish":"Un viaje corto me ha abierto la mente a otras formas de vivir.","english":"A short trip has opened my mind to other ways of living."}},{"question":{"spanish":"\xbfQu\xe9 meta has cumplido hasta ahora este a\xf1o?","english":"What goal have you achieved so far this year?"},"answer":{"spanish":"Hasta ahora he cumplido mi meta de leer doce libros.","english":"So far I have achieved my goal of reading twelve books."}}]}}}')}}]);